import{_ as r,o as a,c as o,a2 as t}from"./chunks/framework.DvFsUg-r.js";const u=JSON.parse('{"title":"플랫폼 관리 프론트엔드 — Research (Phase 0)","description":"","frontmatter":{"title":"플랫폼 관리 프론트엔드 — Research (Phase 0)","feature_id":"006","created":"2026-05-31 16:40 (KST)","date":"2026-05-31T00:00:00.000Z"},"headers":[],"relativePath":"specs/006-platform-admin-frontend/research.md","filePath":"specs/006-platform-admin-frontend/research.md","lastUpdated":null}'),i={name:"specs/006-platform-admin-frontend/research.md"};function s(n,e,l,d,c,p){return a(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="research-플랫폼-관리-프론트엔드" tabindex="-1">Research: 플랫폼 관리 프론트엔드 <a class="header-anchor" href="#research-플랫폼-관리-프론트엔드" aria-label="Permalink to &quot;Research: 플랫폼 관리 프론트엔드&quot;">​</a></h1><p>plan 의 NEEDS CLARIFICATION/위험 항목을 결정으로 해소한다.</p><h2 id="r1-api-클라이언트-—-axios-openapi-typescript-타입만" tabindex="-1">R1. API 클라이언트 — axios + openapi-typescript(타입만) <a class="header-anchor" href="#r1-api-클라이언트-—-axios-openapi-typescript-타입만" aria-label="Permalink to &quot;R1. API 클라이언트 — axios + openapi-typescript(타입만)&quot;">​</a></h2><ul><li><strong>Decision</strong>: HTTP 는 <strong>axios</strong>(lego 답습, 인터셉터로 JWT·401 refresh·ApiResponse 언랩). 타입은 005 <code>/v3/api-docs</code> 에서 <strong>openapi-typescript</strong> 로 생성(<code>types/api.d.ts</code>).</li><li><strong>Rationale</strong>: 런타임 클라이언트 락인 없이 타입 안전 확보. axios 인터셉터가 토큰 갱신· 표준 오류 처리에 적합. lego 와 동일 패턴 → 적응 비용 최소.</li><li><strong>Alternatives</strong>: openapi-fetch/orval(런타임 생성 클라이언트) — 인터셉터 커스터마이즈가 덜 유연. 순수 fetch — 인터셉터·취소·진행률 직접 구현 부담.</li></ul><h2 id="r2-spa-라우팅-모드-딥링크-—-history-forward" tabindex="-1">R2. SPA 라우팅 모드 &amp; 딥링크 — history + forward <a class="header-anchor" href="#r2-spa-라우팅-모드-딥링크-—-history-forward" aria-label="Permalink to &quot;R2. SPA 라우팅 모드 &amp; 딥링크 — history + forward&quot;">​</a></h2><ul><li><strong>Decision</strong>: Vue Router <strong>history 모드</strong>, base <code>/app/</code>. 백엔드에 <code>/app/**</code>→<code>/app/index.html</code> forward 뷰컨트롤러 추가 + SecurityConfig <code>/app/**</code> 공개.</li><li><strong>Rationale</strong>: 깔끔한 URL. forward 한 줄로 딥링크 404 해소. 정적 리소스라 인증 불필요.</li><li><strong>Alternatives</strong>: hash 모드(<code>/app/#/users</code>) — 백엔드 변경 0 이나 URL 미려도↓, 일부 분석/링크 이슈. 채택 안 함(forward 비용이 작음).</li></ul><h2 id="r3-vue-router-버전" tabindex="-1">R3. Vue Router 버전 <a class="header-anchor" href="#r3-vue-router-버전" aria-label="Permalink to &quot;R3. Vue Router 버전&quot;">​</a></h2><ul><li><strong>Decision</strong>: Vue 3.5 호환 <strong>Vue Router 4.x</strong> 최신으로 설치(스캐폴드 시 lock). lego 표기 <code>5.0.3</code> 은 설치 시점에 실재·호환 확인 후 따른다.</li><li><strong>Rationale</strong>: Vue Router 4 가 Vue 3 공식 라인. 잘못된 메이저 고정 회피.</li><li><strong>Alternatives</strong>: lego 표기 그대로 5.0.3 — 실재/호환 미검증이라 설치 시 확정.</li></ul><h2 id="r4-vugrid-통합" tabindex="-1">R4. VuGrid 통합 <a class="header-anchor" href="#r4-vugrid-통합" aria-label="Permalink to &quot;R4. VuGrid 통합&quot;">​</a></h2><ul><li><strong>Decision</strong>: 반입 산출물(<code>C:/ax/vugrid</code> → repo <code>vendor/vugrid</code>)을 <strong>로컬 파일 의존 또는 005 의 <code>/vugrid</code> 정적 서빙(importmap)</strong> 으로 연결. 공통 <code>DataGrid.vue</code> 래퍼로 검색·필터·페이징·정렬을 캡슐화해 화면들이 재사용.</li><li><strong>Rationale</strong>: 대량 목록(감사·사용자) 가상 스크롤. 헌법 참조출처 규약. 래퍼로 결합도 격리.</li><li><strong>Alternatives</strong>: Vuetify <code>v-data-table</code>(서버 페이징) — 소규모엔 충분하나 수만 행 가상 스크롤은 VuGrid 우위. 혼용 가능(작은 목록은 v-data-table). spike 로 확정.</li></ul><h2 id="r5-빌드-통합-—-gradle-node-플러그인-→-spring-static" tabindex="-1">R5. 빌드 통합 — Gradle node 플러그인 → Spring static <a class="header-anchor" href="#r5-빌드-통합-—-gradle-node-플러그인-→-spring-static" aria-label="Permalink to &quot;R5. 빌드 통합 — Gradle node 플러그인 → Spring static&quot;">​</a></h2><ul><li><strong>Decision</strong>: <code>com.github.node-gradle.node</code> 로 <code>gradle :app:build</code> 시 <code>npm ci &amp;&amp; vite build</code> 실행, <code>outDir = src/main/resources/static/app</code>. dev 는 <code>npm run dev</code>(Vite :5173, <code>/api</code> 프록시→:8080).</li><li><strong>Rationale</strong>: 단일 빌드(lego 의 frontend-maven-plugin 의 Gradle 대응). 배포 동일 출처.</li><li><strong>Alternatives</strong>: 프론트 빌드 분리 + CI 복사 — 파이프라인 단순하나 로컬 일관성↓.</li></ul><h2 id="r6-인증-토큰-보관-갱신" tabindex="-1">R6. 인증 토큰 보관 &amp; 갱신 <a class="header-anchor" href="#r6-인증-토큰-보관-갱신" aria-label="Permalink to &quot;R6. 인증 토큰 보관 &amp; 갱신&quot;">​</a></h2><ul><li><strong>Decision</strong>: <strong>Access 토큰은 메모리(authStore)</strong>, refresh 는 응답 인터셉터에서 401 시 <code>/auth/refresh</code> 호출→원요청 재시도. refresh 실패 시 로그아웃→로그인 라우트.</li><li><strong>Rationale</strong>: XSS 노출면 축소(localStorage 회피). 끊김 없는 세션(SC-4).</li><li><strong>Alternatives</strong>: localStorage 보관(새로고침 지속) — 편의↑ 보안↓. 절충: refresh 토큰만 httpOnly 쿠키가 이상적이나 백엔드 무변경 제약상 인터셉터 방식 채택(후속 개선 여지).</li></ul><h2 id="r7-테스트-전략" tabindex="-1">R7. 테스트 전략 <a class="header-anchor" href="#r7-테스트-전략" aria-label="Permalink to &quot;R7. 테스트 전략&quot;">​</a></h2><ul><li><strong>Decision</strong>: <strong>Vitest + @vue/test-utils</strong> 로 ① authStore(401→refresh→재시도), ② 라우터 가드(미인증·권한 차단), ③ DataGrid(검색/페이징), ④ 대표 화면 마운트. 백엔드 통합은 004 의 <code>gradle test</code> 가 담당(무변경 회귀).</li><li><strong>Rationale</strong>: 프론트 로직(스토어·가드·컴포넌트) 단위 검증이 가성비 최적. E2E 는 후속.</li><li><strong>Alternatives</strong>: Playwright E2E — 가치 크나 MVP 범위 밖(앱 기동+Oracle 필요).</li></ul><h2 id="미해소-스캐폴드-구현-시-확정" tabindex="-1">미해소(스캐폴드/구현 시 확정) <a class="header-anchor" href="#미해소-스캐폴드-구현-시-확정" aria-label="Permalink to &quot;미해소(스캐폴드/구현 시 확정)&quot;">​</a></h2><ul><li>정확한 패치 버전 → <code>package-lock.json</code>.</li><li>VuGrid 연결 방식(로컬 의존 vs importmap) → spike 결과로 택1.</li></ul>',18)])])}const h=r(i,[["render",s]]);export{u as __pageData,h as default};
